module RefModule(
    in_1, 
    in_2, 
    out, 
    CTRL
    );parameter BITWIDTH = 32;

    input [BITWIDTH-1 : 0]  in_1;
    input [BITWIDTH-1 : 0]  in_2;
    input                   CTRL;

    output [BITWIDTH-1 : 0] out;

    wire __CTRL_tmp = (CTRL == 1'b0);
    assign out = __CTRL_tmp ? in_1 : in_2;

endmodule
